import random


class Solution:
    def __init__(self, w):
        self.w = w
        self.total = sum(w)

    def pickIndex(self):
        target = random.randint(1, self.total)
        cum = 0
        for i, x in enumerate(self.w):
            cum += x
            if cum >= target:
                return i
        return len(self.w) - 1

