var Solution = function(w) {
    this.prefix = [];
    let total = 0;
    for (const x of w) {
        total += x;
        this.prefix.push(total);
    }
    this.total = total;
};

Solution.prototype.pickIndex = function() {
    const target = Math.floor(Math.random() * this.total) + 1;
    let lo = 0, hi = this.prefix.length - 1;
    while (lo < hi) {
        const mid = (lo + hi) >> 1;
        if (this.prefix[mid] < target) lo = mid + 1;
        else hi = mid;
    }
    return lo;
};
